// Suporte a webhook (body aninhado) e executeWorkflow (json direto)
const raw = $input.first().json;
const body = raw.body || raw;
const acao = body.acao;
const dados = body.dados || {};

if (!acao) throw new Error('Campo "acao" é obrigatório. Valores aceitos: criar_bairro, criar_bairro_planejado, criar_imovel, editar_imovel, buscar_imoveis, upload_foto, gerar_descricao');

function slugify(nome) {
  return (nome || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

let result = { acao, operationType: 'mutation', revalidateTag: 'imovel' };

switch(acao) {

  case 'criar_bairro': {
    const slug = dados.slug || slugify(dados.nome);
    result.mutations = [{ createOrReplace: {
      _id: `bairro-${slug}`,
      _type: 'bairro',
      nome: dados.nome,
      slug: { _type: 'slug', current: slug },
      cidade: dados.cidade || 'Rio de Janeiro',
      estado: dados.estado || 'RJ',
      mercado: dados.mercado || 'barra',
      regiao: dados.regiao || '',
      zona: dados.zona || '',
      ordem: Number(dados.ordem) || 99,
      bairroplanejado: false
    }}];
    result.revalidateTag = 'bairro';
    break;
  }

  case 'criar_bairro_planejado': {
    const slug = dados.slug || slugify(dados.nome);
    result.mutations = [{ createOrReplace: {
      _id: `bairro-${slug}`,
      _type: 'bairro',
      nome: dados.nome,
      slug: { _type: 'slug', current: slug },
      cidade: dados.cidade || 'Rio de Janeiro',
      estado: dados.estado || 'RJ',
      mercado: dados.mercado || 'barra',
      regiao: dados.regiao || 'Zona Oeste',
      zona: dados.zona || 'Oeste',
      ordem: Number(dados.ordem) || 99,
      bairroplanejado: true,
      incorporadora: dados.incorporadora || '',
      introTexto: dados.introTexto || '',
      anoInauguracao: dados.anoInauguracao ? Number(dados.anoInauguracao) : null,
      metaTitle: dados.metaTitle || `${dados.nome} | Bairro Planejado | Admirata`,
      metaDescription: dados.metaDescription || ''
    }}];
    result.revalidateTag = 'bairro';
    break;
  }

  case 'criar_imovel': {
    if (!dados.titulo) throw new Error('criar_imovel requer dados.titulo');
    if (!dados.bairroId) throw new Error('criar_imovel requer dados.bairroId');
    const slug = dados.slug || slugify(dados.titulo);
    const doc = {
      _id: `imovel-${slug}`,
      _type: 'imovel',
      titulo: dados.titulo,
      slug: { _type: 'slug', current: slug },
      status: dados.status || 'Disponível',
      finalidade: dados.finalidade || 'Venda',
      tipo: dados.tipo || 'Apartamento',
      destaque: dados.destaque === true || dados.destaque === 'true',
      preco: dados.preco ? Number(dados.preco) : null,
      precoCondominio: dados.precoCondominio ? Number(dados.precoCondominio) : null,
      quartos: dados.quartos ? Number(dados.quartos) : null,
      suites: dados.suites ? Number(dados.suites) : null,
      banheiros: dados.banheiros ? Number(dados.banheiros) : null,
      vagas: dados.vagas ? Number(dados.vagas) : null,
      areaUtil: dados.areaUtil ? Number(dados.areaUtil) : null,
      areaTotal: dados.areaTotal ? Number(dados.areaTotal) : null,
      descricao: dados.descricao || '',
      endereco: dados.endereco || ''
    };
    if (dados.bairroId) doc.bairro = { _type: 'reference', _ref: dados.bairroId };
    if (dados.condominioId) doc.condominio = { _type: 'reference', _ref: dados.condominioId };
    result.mutations = [{ createOrReplace: doc }];
    break;
  }

  case 'editar_imovel': {
    if (!dados._id) throw new Error('editar_imovel requer dados._id');
    const set = {};
    const numericos = ['preco','precoCondominio','quartos','suites','banheiros','vagas','areaUtil','areaTotal','andar'];
    const campos = [...numericos,'titulo','status','tipo','finalidade','descricao','endereco','destaque','metaTitle','metaDescription'];
    for (const c of campos) {
      if (dados[c] !== undefined) set[c] = numericos.includes(c) ? Number(dados[c]) : dados[c];
    }
    if (dados.bairroId) set.bairro = { _type: 'reference', _ref: dados.bairroId };
    if (dados.condominioId) set.condominio = { _type: 'reference', _ref: dados.condominioId };
    result.mutations = [{ patch: { id: dados._id, set } }];
    break;
  }

  case 'buscar_imoveis': {
    const filtros = [
      `_type == 'imovel'`,
      `finalidade == '${dados.finalidade || 'Venda'}'`,
      `status == 'Disponível'`
    ];
    if (dados.bairro) filtros.push(`bairro->slug.current == '${dados.bairro}'`);
    if (dados.tipo) filtros.push(`tipo == '${dados.tipo}'`);
    if (dados.quartos) filtros.push(`quartos >= ${Number(dados.quartos)}`);
    if (dados.precoMin) filtros.push(`preco >= ${Number(dados.precoMin)}`);
    if (dados.precoMax) filtros.push(`preco <= ${Number(dados.precoMax)}`);
    if (dados.destaque) filtros.push(`destaque == true`);
    const por = Number(dados.por_pagina) || 20;
    const pag = Number(dados.pagina) || 1;
    const offset = (pag - 1) * por;
    result.groq = encodeURIComponent(
      `*[${filtros.join(' && ')}]|order(destaque desc,_createdAt desc)[${offset}...${offset+por}]{_id,titulo,slug,status,tipo,preco,precoCondominio,quartos,suites,banheiros,vagas,areaUtil,areaTotal,destaque,'bairro':bairro->{nome,slug},'condominio':condominio->{nome,slug},'fotoCapa':fotoCapa{asset->{url,metadata{lqip}},hotspot,crop}}`
    );
    result.operationType = 'query';
    break;
  }

  case 'upload_foto': {
    if (!dados.documentoId) throw new Error('upload_foto requer dados.documentoId');
    if (!dados.imagemUrl) throw new Error('upload_foto requer dados.imagemUrl');
    result.operationType = 'upload';
    result.dados = dados;
    break;
  }

  case 'gerar_descricao': {
    if (!dados._id) throw new Error('gerar_descricao requer dados._id');
    result.operationType = 'descricao';
    result.dados = dados;
    break;
  }

  default:
    throw new Error(`Ação desconhecida: "${acao}". Válidas: criar_bairro, criar_bairro_planejado, criar_imovel, editar_imovel, buscar_imoveis, upload_foto, gerar_descricao`);
}

return [{ json: result }];

const assetId = $input.first().json.document._id;
const d = $('Router — Parsear e validar ação').item.json.dados;
const campo = d.campo || 'fotoCapa';

const mutations = campo === 'fotos'
  ? [{ patch: { id: d.documentoId, insert: { after: 'fotos[-1]', items: [{ _type: 'foto', _key: `foto_${Date.now()}`, asset: { _type: 'reference', _ref: assetId }, legenda: d.legenda || '' }] } } }]
  : [{ patch: { id: d.documentoId, set: { [campo]: { _type: 'image', asset: { _type: 'reference', _ref: assetId } } } } }];

return [{ json: { mutations, assetId, documentoId: d.documentoId, campo } }];

const imovel = $('Sanity — Buscar dados do imóvel').item.json.result;
const d = $('Router — Parsear e validar ação').item.json.dados;

if (!imovel) throw new Error(`Imóvel não encontrado: ${d._id}`);

const tom = d.tom || 'sofisticado';
const foco = d.focusSEO || `${imovel.tipo || 'imóvel'} ${(imovel.finalidade || 'venda').toLowerCase()} ${imovel.bairro?.nome || ''}`;

const toms = {
  sofisticado: 'Tom refinado e aspiracional para compradores de alto padrão que valorizam exclusividade.',
  direto: 'Tom objetivo e informativo, destacando os principais atributos sem rodeios.',
  emocional: 'Tom envolvente que cria conexão emocional e pinta um quadro vívido da vida no imóvel.'
};

const detalhes = [
  imovel.tipo && `Tipo: ${imovel.tipo}`,
  imovel.finalidade && `Finalidade: ${imovel.finalidade}`,
  imovel.quartos && `${imovel.quartos} quartos${imovel.suites ? `, ${imovel.suites} suíte(s)` : ''}`,
  imovel.banheiros && `${imovel.banheiros} banheiro(s)`,
  imovel.vagas && `${imovel.vagas} vaga(s)`,
  imovel.areaUtil && `${imovel.areaUtil}m² úteis`,
  imovel.areaTotal && `${imovel.areaTotal}m² totais`,
  imovel.andar && `${imovel.andar}º andar`,
  imovel.bairro?.nome && `Bairro: ${imovel.bairro.nome}`,
  imovel.condominio?.nome && `Condomínio: ${imovel.condominio.nome}`
].filter(Boolean).join('\n');

const prompt = `Você é especialista em copywriting imobiliário de luxo para o mercado do Rio de Janeiro.\n\n${toms[tom]}\n\nCrie uma descrição de 200 a 260 palavras em português brasileiro para o imóvel abaixo.\nRegras:\n- Otimizada para SEO com foco em: "${foco}"\n- Sem bullet points\n- Sem mencionar preço\n- Termine com chamada para ação discreta\n\nDados:\n${detalhes}\n\nRetorne APENAS o texto da descrição.`;

return [{ json: { prompt, imovelId: imovel._id } }];

const texto = $input.first().json.choices?.[0]?.message?.content?.trim() || '';
const imovelId = $('Code — Montar prompt IA').item.json.imovelId;
if (!texto) throw new Error('OpenAI não retornou conteúdo');
return [{ json: { mutations: [{ patch: { id: imovelId, set: { descricao: texto } } }], descricao: texto, imovelId } }];
